sub _r { my ($a) = @_; return $a->[int(rand(scalar @$a))]; }
sub _ph { my $p = _r(\@phone_prefixes); return "$p-" . (int(rand(900))+100) . "-" . (int(rand(9000))+1000); }
sub _em {
  my ($f,$l) = @_; my $d = _r(\@email_domains);
  my $a = int(rand(5));
  if ($a == 0) { return lc("$f.$l\@$d"); }
  elsif ($a == 1) { return lc("$f$l\@$d"); }
  elsif ($a == 2) { return lc((substr($f,0,1)) . $l . int(rand(100)) . "\@$d"); }
  elsif ($a == 3) { return lc("$f.$l" . (int(rand(99))+1) . "\@$d"); }
  return lc("$f" . int(rand(99)) . "\@$d");
}
sub _u {
  my $f = _r(\@first_names); my $l = _r(\@last_names);
  return {
    name => "$f $l", first_name => $f, last_name => $l,
    email => _em($f,$l), phone => _ph(),
    city => _r(\@cities),
    street_address => (int(rand(9000))+100) . " " . _r(\@streets),
    zip_code => sprintf("%05d", int(rand(90000))+10000),
    profession => _r(\@professions),
    age => int(rand(50)) + 18,
  };
}
sub _c {
  my $co = _r(\@companies); my $d = lc($co); $d =~ s/[^a-z0-9]//g;
  return {
    company_name => $co, industry => _r(\@industries),
    city => _r(\@cities),
    phone => _ph(), email => "info\@$d.com", website => "https://www.$d.com",
    employee_count => int(rand(9000)) + 100,
    founded_year => int(rand(50)) + 1970,
  };
}
my $type = $args->{type} // 'user';
if ($type eq 'user' || $type eq 'person') { return _u(); }
elsif ($type eq 'company') { return _c(); }
elsif ($type eq 'address') {
  return {
    street_address => (int(rand(9000))+100) . " " . _r(\@streets),
    city => _r(\@cities), zip_code => sprintf("%05d", int(rand(90000))+10000),
  };
}
elsif ($type eq 'all') { return { user => _u(), company => _c() }; }
else { return { error => "Unknown type '$type'. Supported: user, person, company, address, all" }; }
